import React, { useEffect, useState } from 'react';
import api from '../utils/api';

const statusStyle = (s: string) => {
  const m: any = {
    borrowed: { bg:'rgba(245,158,11,0.12)', color:'#d97706' },
    returned: { bg:'rgba(16,185,129,0.12)',  color:'#059669' },
    overdue:  { bg:'rgba(239,68,68,0.12)',   color:'#dc2626' },
    pending:  { bg:'rgba(245,158,11,0.12)',  color:'#d97706' },
    approved: { bg:'rgba(16,185,129,0.12)',  color:'#059669' },
    rejected: { bg:'rgba(239,68,68,0.12)',   color:'#dc2626' },
  };
  return m[s] || { bg:'rgba(107,114,128,0.12)', color:'#6b7280' };
};

export default function MyBorrows() {
  const [borrows, setBorrows]   = useState<any[]>([]);
  const [requests, setRequests] = useState<any[]>([]);
  const [loading, setLoading]   = useState(true);
  const [tab, setTab] = useState<'requests' | 'borrows'>('requests');

  const load = () => {
    setLoading(true);
    Promise.all([api.get('/borrows/my'), api.get('/borrows/my-requests')])
      .then(([b, r]) => {
        setBorrows(b.data.data || []);
        setRequests(r.data.data || []);
        setLoading(false);
      })
      .catch(() => setLoading(false));
  };

  useEffect(() => { load(); }, []);

  const hideRequest = async (id: number) => {
    await api.delete(`/borrows/my-requests/${id}`);
    setRequests(prev => prev.filter(r => r.id !== id));
  };

  const pendingCount = requests.filter(r => r.status === 'pending').length;

  return (
    <div className="page-enter" style={{ padding:'32px 40px', width:'100%' }}>

      {/* Header */}
      <div style={{ marginBottom:28 }}>
        <h1 style={{ fontFamily:"'Playfair Display',serif", fontSize:32, fontWeight:700, color:'var(--text)' }}>My Library</h1>
        <p style={{ color:'var(--text-muted)', fontSize:14, marginTop:6 }}>Your borrow history and requests</p>
      </div>

      {/* Tabs */}
      <div style={{ display:'flex', gap:8, marginBottom:26 }}>
        {(['requests','borrows'] as const).map(t => (
          <button key={t} onClick={() => setTab(t)}
            style={{
              padding:'10px 22px',
              background: tab===t ? '#c9a84c' : 'var(--bg2)',
              color: tab===t ? '#1a1a2e' : 'var(--text-dim)',
              border: tab===t ? 'none' : '1px solid var(--border)',
              borderRadius:10, fontSize:14, fontWeight:700,
              fontFamily:'inherit', transition:'all .2s',
              display:'flex', alignItems:'center', gap:8,
              boxShadow: tab===t ? '0 4px 14px rgba(201,168,76,0.3)' : 'none',
              cursor:'pointer',
            }}>
            {t === 'requests' ? 'My Requests' : 'Borrowed Books'}
            {t === 'requests' && pendingCount > 0 && (
              <span style={{ background:'#1a1a2e', color:'#c9a84c', borderRadius:99, padding:'1px 8px', fontSize:11, fontWeight:800 }}>
                {pendingCount}
              </span>
            )}
          </button>
        ))}
      </div>

      {loading ? (
        <div style={{ display:'flex', justifyContent:'center', padding:80 }}>
          <div style={{ width:32, height:32, border:'3px solid #c9a84c', borderTopColor:'transparent', borderRadius:'50%', animation:'spin 1s linear infinite' }}/>
        </div>
      ) : tab === 'requests' ? (

        /* ── My Requests ── */
        requests.length ? (
          <div style={{ display:'grid', gap:12 }}>
            {requests.map(r => {
              const st = statusStyle(r.status);
              const canDelete = r.status === 'rejected' || r.status === 'approved';
              return (
                <div key={r.id} className="hover-card"
                  style={{ background:'var(--bg2)', border:'1px solid var(--border)', borderRadius:16, padding:'20px 22px', display:'flex', alignItems:'center', gap:20 }}>

                  {/* Status dot */}
                  <div style={{ width:10, height:10, borderRadius:'50%', background:st.color, flexShrink:0, boxShadow:`0 0 8px ${st.color}66` }}/>

                  {/* Info */}
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ fontSize:16, fontWeight:700, color:'var(--text)', marginBottom:4, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{r.title}</div>
                    <div style={{ fontSize:13, color:'var(--text-dim)' }}>{r.author}</div>
                    <div style={{ fontSize:12, color:'var(--text-muted)', marginTop:6 }}>
                      Requested: {new Date(r.request_date).toLocaleDateString('en-GB', { day:'numeric', month:'short', year:'numeric' })}
                    </div>
                  </div>

                  {/* Status + delete */}
                  <div style={{ display:'flex', alignItems:'center', gap:10, flexShrink:0 }}>
                    <div style={{ textAlign:'right' }}>
                      <span style={{ fontSize:12, fontWeight:700, padding:'5px 14px', borderRadius:99, background:st.bg, color:st.color, display:'inline-block', textTransform:'capitalize' }}>
                        {r.status}
                      </span>
                      {r.reject_reason && (
                        <div style={{ fontSize:11, color:'#dc2626', marginTop:5, maxWidth:180, textAlign:'right' }}>
                          Reason: {r.reject_reason}
                        </div>
                      )}
                    </div>

                    {/* Delete button — only for rejected or approved */}
                    {canDelete && (
                      <button
                        onClick={() => hideRequest(r.id)}
                        title="Remove from list"
                        style={{
                          width:34, height:34, borderRadius:9,
                          background:'var(--bg3)', border:'1px solid var(--border)',
                          color:'var(--text-muted)', cursor:'pointer',
                          display:'flex', alignItems:'center', justifyContent:'center',
                          fontSize:15, transition:'all .18s', flexShrink:0,
                        }}
                        onMouseEnter={e => {
                          const b = e.currentTarget;
                          b.style.background = 'rgba(239,68,68,0.1)';
                          b.style.color = '#ef4444';
                          b.style.borderColor = 'rgba(239,68,68,0.25)';
                          b.style.transform = 'scale(1.05)';
                        }}
                        onMouseLeave={e => {
                          const b = e.currentTarget;
                          b.style.background = 'var(--bg3)';
                          b.style.color = 'var(--text-muted)';
                          b.style.borderColor = 'var(--border)';
                          b.style.transform = 'scale(1)';
                        }}>
                        ✕
                      </button>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        ) : (
          <div style={{ textAlign:'center', padding:'80px 0' }}>
            <div style={{ fontSize:14, color:'var(--text-muted)', fontStyle:'italic', marginBottom:8 }}>No requests yet</div>
            <div style={{ fontSize:13, color:'var(--text-muted)' }}>Go to Books page and click "Request Borrow"</div>
          </div>
        )

      ) : (

        /* ── Borrowed Books ── */
        borrows.length ? (
          <div style={{ display:'grid', gap:12 }}>
            {borrows.map(b => {
              const st = statusStyle(b.status);
              return (
                <div key={b.id} className="hover-card"
                  style={{ background:'var(--bg2)', border:`1px solid ${b.status==='overdue'?'rgba(239,68,68,0.3)':'var(--border)'}`, borderRadius:16, padding:'20px 22px', display:'flex', alignItems:'center', gap:20 }}>
                  <div style={{ width:10, height:10, borderRadius:'50%', background:st.color, flexShrink:0, boxShadow:`0 0 8px ${st.color}66` }}/>
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ fontSize:16, fontWeight:700, color:'var(--text)', marginBottom:4, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{b.title}</div>
                    <div style={{ fontSize:13, color:'var(--text-dim)' }}>{b.author}</div>
                    <div style={{ fontSize:12, color:'var(--text-muted)', marginTop:6 }}>Due: {b.due_date?.split('T')[0]}</div>
                  </div>
                  <div style={{ textAlign:'right', flexShrink:0 }}>
                    <span style={{ fontSize:12, fontWeight:700, padding:'5px 14px', borderRadius:99, background:st.bg, color:st.color, display:'inline-block', textTransform:'capitalize', marginBottom:b.fine_amount>0?6:0 }}>
                      {b.status}
                    </span>
                    {b.fine_amount > 0 && (
                      <div style={{ fontSize:13, fontWeight:800, color:'#dc2626' }}>Fine: ৳{Number(b.fine_amount).toFixed(2)}</div>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        ) : (
          <div style={{ textAlign:'center', padding:'80px 0', color:'var(--text-muted)', fontSize:14, fontStyle:'italic' }}>
            No books borrowed yet
          </div>
        )
      )}
    </div>
  );
}
